  1→import { useEffect, useMemo, useState } from "react";
  2→import { MoonLoader } from "react-spinners";
  3→import { useInfiniteQuery } from "@tanstack/react-query";
  4→import { useNavigate } from "react-router-dom";
  5→import { useInView } from "react-intersection-observer";
  6→import { getCanvasGallery } from "../../../../API/Api";
  7→import { useAuth } from "../../../Context/useAuth";
  8→import formatPostDate from "../../../../helpers/formatDateString";
  9→import { handleClickProfile } from "../../../../helpers/handleClicks";
 10→import VerifiedBadge from "../../Badge/VerifiedBadge";
 11→import { getCanvasPreview } from "../../../utils/canvasDoc";
 12→import CanvasPreview from "../postCards/CanvasPreview/CanvasPreview";
 13→import CalculateText from "../postCards/calculateReadingTime";
 14→import "./gallery.css";
 15→
 16→const CANVAS_GALLERY_PAGE_SIZE = 5;
 17→
 18→const GalleryPage = () => {
 19→    const navigate = useNavigate();
 20→    const {session, user, openAuthModal} = useAuth();
 21→    const handleClickUserProfileOriginal = handleClickProfile(navigate);
 22→    const userId = user?.userData?.[0]?.id || null;
 23→    const [sortMode, setSortMode] = useState('hottest');
 24→    const {ref: inViewRef, inView} = useInView({threshold: 0.1});
 25→
 26→    const {
 27→        data,
 28→        isLoading,
 29→        isFetching,
 30→        isFetchingNextPage,
 31→        fetchNextPage,
 32→        hasNextPage
 33→    } = useInfiniteQuery({
 34→        queryKey: ['canvasGallery', userId, sortMode],
 35→        queryFn: ({pageParam = null}) => getCanvasGallery(userId, CANVAS_GALLERY_PAGE_SIZE, sortMode, pageParam),
 36→        initialPageParam: null,
 37→        getNextPageParam: (lastPage) => (lastPage?.hasMore ? lastPage?.nextCursor : undefined),
 38→        refetchOnWindowFocus: false,
 39→        staleTime: 1000 * 45
 40→    });
 41→
 42→    useEffect(() => {
 43→        if(inView && hasNextPage && !isFetchingNextPage){
 44→            fetchNextPage();
 45→        }
 46→    }, [inView, hasNextPage, isFetchingNextPage, fetchNextPage]);
 47→
 48→    const journals = useMemo(() => (
 49→        (data?.pages || [])
 50→            .flatMap((page) => page?.data || [])
 51→            .filter((journal) => journal?.post_type === "canvas")
 52→    ), [data?.pages]);
 53→
 54→    const handleOpenCanvas = (journalId) => {
 55→        if(!session){
 56→            openAuthModal();
 57→            return;
 58→        }
 59→        navigate(`/home/post/${journalId}`);
 60→    };
 61→
 62→    const handleClickUserProfile = (event, clickedUserId) => {
 63→        event.stopPropagation();
 64→        if(!session){
 65→            openAuthModal();
 66→            return;
 67→        }
 68→        handleClickUserProfileOriginal(event, userId, clickedUserId);
 69→    };
 70→
 71→    const handleRemixCanvas = (event, journal) => {
 72→        event.stopPropagation();
 73→        if(!session){
 74→            openAuthModal();
 75→            return;
 76→        }
 77→
 78→        const sourceTitle = typeof journal?.title === 'string' ? journal.title.trim() : '';
 79→        const remixTitle = sourceTitle.toLowerCase().startsWith('remix:')
 80→            ? sourceTitle
 81→            : `Remix: ${sourceTitle || 'Canvas'}`;
 82→
 83→        navigate('/home', {
 84→            state: {
 85→                openEditor: true,
 86→                editorMode: 'canvas',
 87→                initialTitle: remixTitle,
 88→                initialCanvasDoc: journal?.canvas_doc || null,
 89→                remixSource: {
 90→                    journalId: journal?.id,
 91→                    authorName: journal?.users?.name || 'Unknown'
 92→                }
 93→            }
 94→        });
 95→    };
 96→
 97→    if(isLoading){
 98→        return (
 99→            <div className="gallery-loading-state">
100→                <MoonLoader loading={isLoading} color="var(--loader-color)" size={20} />
101→            </div>
102→        );
103→    }
104→
105→    return (
106→        <div className="gallery-page-root">
107→            <div className="gallery-top-bar">
108→                <div className="gallery-title-shell">
109→                    <h2 className="gallery-title">Gallery</h2>
110→                    <p className="gallery-subtitle">Canvas posts arranged as visual pieces</p>
111→                </div>
112→
113→                <div className="gallery-sort-shell">
114→                    <button
115→                        type="button"
116→                        className={`gallery-sort-btn ${sortMode === 'hottest' ? 'is-active' : ''}`}
117→                        onClick={() => setSortMode('hottest')}
118→                    >
119→                        Hottest
120→                    </button>
121→                    <button
122→                        type="button"
123→                        className={`gallery-sort-btn ${sortMode === 'newest' ? 'is-active' : ''}`}
124→                        onClick={() => setSortMode('newest')}
125→                    >
126→                        Newest
127→                    </button>
128→                </div>
129→            </div>
130→
131→            {isFetching && !isFetchingNextPage && (
132→                <div className="gallery-refresh-pill">Refreshing...</div>
133→            )}
134→
135→            {journals.length === 0 ? (
136→                <div className="gallery-empty-state">No public canvases yet.</div>
137→            ) : (
138→                <>
139→                    <div className="gallery-cards">
140→                        {journals.map((journal) => {
141→                            const canvasPreview = getCanvasPreview(journal?.canvas_doc);
142→                            const previewText = canvasPreview?.slicedText || 'No text added to this canvas yet.';
143→                            const wholeText = canvasPreview?.wholeText || '';
144→
145→                            return (
146→                            <article
147→                                key={journal.id}
148→                                className="gallery-canvas-card"
149→                                onClick={() => handleOpenCanvas(journal.id)}
150→                                role="button"
151→                                tabIndex={0}
152→                                onKeyDown={(event) => {
153→                                    if(event.key === 'Enter' || event.key === ' '){
154→                                        event.preventDefault();
155→                                        handleOpenCanvas(journal.id);
156→                                    }
157→                                }}
158→                            >
159→                                <CanvasPreview canvasDoc={journal?.canvas_doc} />
160→                                <div className="gallery-canvas-content">
161→                                    <div className="gallery-content-container">
162→                                        <div className="gallery-feed-text-content-container">
163→                                            <div className="gallery-feed-title-content">
164→                                                <span className="gallery-canvas-type-badge">
165→                                                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor"
166→                                                         strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
167→                                                        <path d="M12 19l7-7 3 3-7 7-3-3z"/>
168→                                                        <path d="M18 13l-1.5-7.5L2 2l3.5 14.5L13 18l5-5z"/>
169→                                                        <path d="M2 2l7.586 7.586"/>
170→                                                        <circle cx="11" cy="11" r="2"/>
171→                                                    </svg>
172→                                                    Canvas
173→                                                </span>
174→                                                <h3 className="gallery-feed-title">
175→                                                    {journal?.title?.length > 55 ? `${journal.title.substring(0, 55)}...` : (journal?.title || 'Untitled Canvas')}
176→                                                </h3>
177→                                            </div>
178→                                            <p className="gallery-feed-text-content">
179→                                                {previewText}
180→                                            </p>
181→                                        </div>
182→                                    </div>
183→
184→                                    <div className="gallery-canvas-actions">
185→                                        <button
186→                                            type="button"
187→                                            className="gallery-canvas-action-btn is-remix"
188→                                            onClick={(event) => handleRemixCanvas(event, journal)}
189→                                        >
190→                                            Remix this Canvas
191→                                        </button>
192→                                    </div>
193→                                </div>
194→
195→                                <div className="gallery-card-footer">
196→                                    <div
197→                                        className="gallery-user-info-child-container"
198→                                        onClick={(event) => handleClickUserProfile(event, journal?.users?.id)}
199→                                    >
200→                                        <div className={`gallery-user-avatar-container ${journal?.users?.badge === 'legend' ? 'avatar-ring-legend' : journal?.users?.badge === 'og' ? 'avatar-ring-og' : ''}`}>
201→                                            <img
202→                                                loading="lazy"
203→                                                className="gallery-user-info-avatar"
204→                                                src={journal?.users?.image_url || '/assets/profile.jpg'}
205→                                                alt={`${journal?.users?.name || "User"} profile picture`}
206→                                            />
207→                                        </div>
208→                                        <div className="gallery-user-name-container">
209→                                            <p className="gallery-user-newsfeed-name">{journal?.users?.name || 'Unknown'}</p>
210→                                            <VerifiedBadge badge={journal?.users?.badge} size={14} />
211→                                        </div>
212→                                        <div className="gallery-name-info-separator">•</div>
213→                                        <p className="gallery-user-post-date">{formatPostDate(journal?.created_at)}</p>
214→                                    </div>
215→
216→                                    <div className="gallery-reading-time-container">
217→                                        <p className="gallery-reading-time-text">{CalculateText(wholeText)}</p>
218→                                    </div>
219→
220→                                    <div className="gallery-card-score">
221→                                        <span>Hot score</span>
222→                                        <span>{journal?.hot_score || 0}</span>
223→                                    </div>
224→                                </div>
225→                            </article>
226→                        )})}
227→                    </div>
228→
229→                    {isFetchingNextPage && (
230→                        <div className="gallery-next-loading">
231→                            <MoonLoader loading={isFetchingNextPage} color="var(--loader-color)" size={16} />
232→                        </div>
233→                    )}
234→
235→                    {hasNextPage && <div ref={inViewRef} className="gallery-infinite-sentinel" />}
236→                </>
237→            )}
238→        </div>
239→    );
240→}
241→
242→export default GalleryPage;
243→

  1→import { RichTextPlugin } from "@lexical/react/LexicalRichTextPlugin";
  2→import { ContentEditable } from "@lexical/react/LexicalContentEditable";
  3→import ImageNode from "../Editor/nodes/ImageNode";
  4→import { HeadingNode, QuoteNode } from "@lexical/rich-text";
  5→import { LexicalComposer } from "@lexical/react/LexicalComposer";
  6→import { LexicalErrorBoundary } from "@lexical/react/LexicalErrorBoundary";
  7→import { useLocation, useNavigate, useParams } from "react-router-dom";
  8→import './contentviewer.css'
  9→import { useEffect, useMemo, useRef, useState } from "react";
 10→import { AnimatePresence, motion } from "framer-motion";
 11→import { MoonLoader } from "react-spinners";
 12→import CalculateText from "../postCards/calculateReadingTime";
 13→import ParseContent from "../postCards/parseData";
 14→import { useBookMarkMutation, useFollowMutation, useLikeMutation, useAddViewsMutation } from "../../../utils/useMutation";
 15→import { useAuth } from "../../../Context/useAuth";
 16→import CommentSection from "../../comments/comments";
 17→import CanvasViewer from "../Canvas/CanvasViewer";
 18→import debounce from "../../../../helpers/debounce";
 19→import formatCounts from "../../../../helpers/fomatCounts";
 20→import { handleClickProfile, handleCLickContent } from "../../../../helpers/handleClicks";
 21→import { getFollowsData, getJournalById } from "../../../../API/Api";
 22→import { useQuery } from "@tanstack/react-query";
 23→import VerifiedBadge from "../../Badge/VerifiedBadge";
 24→import { getCanvasWholeText, parseCanvasDoc } from "../../../utils/canvasDoc";
 25→import RepostModal from "../../RepostModal/RepostModal";
 26→import ShareMenu from "../../ShareMenu/ShareMenu";
 27→import getShareUrl from "../../../utils/getShareUrl";
 28→import usePostSeo from "../../../seo/usePostSeo";
 29→
 30→const normalizeInteractionFlag = (value) => {
 31→    if(typeof value === 'boolean') return value;
 32→    if(typeof value === 'string'){
 33→        const normalized = value.trim().toLowerCase();
 34→        if(normalized === 'true') return true;
 35→        if(normalized === 'false') return false;
 36→    }
 37→    if(typeof value === 'number'){
 38→        return value === 1;
 39→    }
 40→    return Boolean(value);
 41→};
 42→
 43→const normalizeCount = (value) => {
 44→    const number = Number(value);
 45→    if(!Number.isFinite(number) || number < 0){
 46→        return 0;
 47→    }
 48→    return number;
 49→};
 50→
 51→const getNextToggleCount = (isActive, currentCount) => {
 52→    return isActive
 53→        ? Math.max(0, currentCount - 1)
 54→        : currentCount + 1;
 55→};
 56→
 57→const ContentView = () => {
 58→    const navigate = useNavigate();
 59→    const [showBackButton, setShowBackButton] = useState(true);
 60→    const { session, user, openAuthModal } = useAuth();
 61→
 62→    const timeOutRef = useRef();
 63→    const timeOutRefBookmark = useRef();
 64→    const likeInFlightRef = useRef(false);
 65→    const bookmarkInFlightRef = useRef(false);
 66→
 67→    const [showCommentsContainer, setShowCommentsContainer] = useState(false);
 68→    const [isLiked, setIsliked] = useState(false);
 69→    const [likesCount, setLikesCount] = useState(0);
 70→    const [isBookmarked, setIsBookmarked] = useState(false);
 71→    const [bookmarkCounts, setBookmarkCounts] = useState(0);
 72→
 73→    const [bookmarkedMessage, setBookmarkedMessage] = useState('');
 74→    const [showRepostModal, setShowRepostModal] = useState(false);
 75→    const [showShareMenu, setShowShareMenu] = useState(false);
 76→
 77→    const contentRef = useRef();
 78→
 79→    const theme = {
 80→        paragraph: 'editor-paragraph',
 81→        heading: {
 82→            h1: 'editor-heading-h1',
 83→            h2: 'editor-heading-h2',
 84→            h3: 'editor-heading-h3',
 85→        },
 86→        quote: 'editor-quote',
 87→        text: {
 88→            bold: 'editor-text-bold',
 89→            italic: 'editor-text-italic',
 90→            underline: 'editor-text-underline',
 91→        }
 92→    }
 93→
 94→    const location = useLocation();
 95→    const { journalId } = useParams();
 96→    const statePostData = location.state;
 97→    const shouldFetchPost = !!journalId && (!statePostData || !statePostData?.postType);
 98→
 99→    const { data: fetchedJournalData, isLoading: isLoadingJournalById } = useQuery({
100→        queryKey: ['journalById', journalId, user?.userData?.[0]?.id],
101→        queryFn: ({ queryKey }) => getJournalById(queryKey[1], queryKey[2]),
102→        enabled: shouldFetchPost,
103→        staleTime: 1000 * 60 * 5,
104→        refetchOnWindowFocus: false,
105→    });
106→
107→    const postData = useMemo(() => {
108→        const journal = fetchedJournalData?.journal;
109→        if(journal){
110→            const postType = journal?.post_type || 'text';
111→            const parsedContent = ParseContent(journal?.content);
112→            const canvasDoc = postType === 'canvas' ? parseCanvasDoc(journal?.canvas_doc) : null;
113→            const wholeText = postType === 'canvas'
114→                ? getCanvasWholeText(canvasDoc)
115→                : (parsedContent?.wholeText || '');
116→
117→            return {
118→                postType: postType,
119→                content: journal?.content,
120→                canvasDoc: canvasDoc,
121→                wholeText: wholeText,
122→                title: journal?.title,
123→                userId: journal?.users?.id || journal?.user_id,
124→                name: journal?.users?.name,
125→                avatar: journal?.users?.image_url,
126→                created_at: journal?.created_at,
127→                journalId: journal?.id,
128→                isLiked: journal?.has_liked,
129→                commentsCount: journal?.comment_count?.[0]?.count || 0,
130→                isBookmarked: journal?.has_bookmarked,
131→                likesCount: journal?.like_count?.[0]?.count || 0,
132→                bookmarksCount: journal?.bookmark_count?.[0]?.count || 0,
133→                badge: journal?.users?.badge,
134→                isRepost: journal?.is_repost === true,
135→                repostCaption: journal?.repost_caption || '',
136→                repostSource: journal?.repost_source || null
137→            };
138→        }
139→
140→        if(!statePostData){
141→            return null;
142→        }
143→
144→        const inferredPostType = statePostData?.postType || (statePostData?.canvasDoc ? 'canvas' : 'text');
145→        const parsedContent = ParseContent(statePostData?.content);
146→        const canvasDoc = inferredPostType === 'canvas' ? parseCanvasDoc(statePostData?.canvasDoc) : null;
147→
148→        return {
149→            postType: inferredPostType,
150→            content: statePostData?.content,
151→            canvasDoc: canvasDoc,
152→            wholeText: inferredPostType === 'canvas'
153→                ? (statePostData?.wholeText || getCanvasWholeText(canvasDoc))
154→                : (statePostData?.wholeText || parsedContent?.wholeText || ''),
155→            title: statePostData?.title,
156→            userId: statePostData?.userId,
157→            name: statePostData?.name,
158→            avatar: statePostData?.avatar,
159→            created_at: statePostData?.created_at,
160→            journalId: statePostData?.journalId,
161→            isLiked: statePostData?.isLiked,
162→            commentsCount: statePostData?.commentsCount || 0,
163→            isBookmarked: statePostData?.isBookmarked,
164→            likesCount: statePostData?.likesCount || 0,
165→            bookmarksCount: statePostData?.bookmarksCount || 0,
166→            badge: statePostData?.badge,
167→            isRepost: statePostData?.isRepost === true,
168→            repostCaption: statePostData?.repostCaption || '',
169→            repostSource: statePostData?.repostSource || null
170→        };
171→    }, [fetchedJournalData, statePostData]);
172→
173→    usePostSeo(postData);
174→
175→    const { data: followsData, isLoading: isLoadingFollows } = useQuery({
176→        queryKey: ['followsData', user?.userData?.[0]?.id, postData?.userId],
177→        queryFn: ({ queryKey }) => getFollowsData(queryKey[1], queryKey[2]),
178→        staleTime: 1000 * 60 * 60,
179→        cacheTime: 1000 * 60 * 60,
180→        enabled: !!user?.userData?.[0]?.id && !!postData?.userId,
181→    });
182→
183→    const handleclickUserProfile = handleClickProfile(navigate);
184→    const viewContent = handleCLickContent(navigate);
185→
186→    const mutateViews = useAddViewsMutation(session);
187→    const mutationLike = useLikeMutation(session, user?.userData?.[0]?.id);
188→    const handleClickLike = async (e, journalId, receiverId, senderImageUrl, sendername, senderEmail) => {
189→        e.stopPropagation();
190→        if(likeInFlightRef.current){
191→            return;
192→        }
193→        if(!session){
194→            openAuthModal?.();
195→            return;
196→        }
197→        const wasLiked = normalizeInteractionFlag(isLiked);
198→        likeInFlightRef.current = true;
199→        setIsliked(!wasLiked);
200→        setLikesCount((prevCount) => getNextToggleCount(wasLiked, normalizeCount(prevCount)));
201→        mutationLike.mutate(
202→            { journalId, receiverId, senderImageUrl, sendername, senderEmail },
203→            {
204→                onSettled: () => {
205→                    likeInFlightRef.current = false;
206→                }
207→            }
208→        );
209→    }
210→
211→    const mutationBookmark = useBookMarkMutation(session, user?.userData?.[0]?.id);
212→    const handleClickBookmark = async (e, journalId) => {
213→        e.stopPropagation();
214→        if(bookmarkInFlightRef.current){
215→            return;
216→        }
217→        if(!session){
218→            openAuthModal?.();
219→            return;
220→        }
221→        const wasBookmarked = normalizeInteractionFlag(isBookmarked);
222→        bookmarkInFlightRef.current = true;
223→        setIsBookmarked(!wasBookmarked);
224→        setBookmarkCounts((prevCount) => getNextToggleCount(wasBookmarked, normalizeCount(prevCount)));
225→        let response = null;
226→        try {
227→            response = await mutationBookmark.mutateAsync({ journalId });
228→        } finally {
229→            bookmarkInFlightRef.current = false;
230→        }
231→        
232→        if(timeOutRefBookmark.current){
233→            clearTimeout(timeOutRefBookmark.current);
234→        }
235→        if (response?.message === 'success') {
236→            setBookmarkedMessage('Post was added to your Bookmarks'); 
237→        } else if(response?.message === 'deleted'){
238→            setBookmarkedMessage('Post was removed from your Bookmarks');
239→        }
240→            
241→        timeOutRefBookmark.current = setTimeout(() => {
242→            setBookmarkedMessage('');
243→        }, 1500);
244→
245→    }
246→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
247→
248→    const mutationFollow = useFollowMutation(session);
249→    const handleClickFollow = async (e, followingId, followerId) => {
250→        e.stopPropagation();
251→        if(!session) return openAuthModal();
252→        mutationFollow.mutate({ followingId, followerId });
253→    }
254→    const debounceClickFollow = debounce(handleClickFollow, 100);
255→
256→    const handleBackLocation = (e) => {
257→        e.stopPropagation();
258→        window.history.back();
259→    }
260→
261→    const hanldeClickComments = (e) => {
262→        e.stopPropagation();
263→        if(!session) return openAuthModal();
264→        setShowCommentsContainer(true);
265→    }
266→
267→    const handleRemixCanvas = (e) => {
268→        e.stopPropagation();
269→        if(!session){
270→            return;
271→        }
272→
273→        const sourceTitle = typeof postData?.title === 'string' ? postData.title.trim() : '';
274→        const remixTitle = sourceTitle.toLowerCase().startsWith('remix:')
275→            ? sourceTitle
276→            : `Remix: ${sourceTitle || 'Canvas'}`;
277→
278→        navigate('/home', {
279→            state: {
280→                openEditor: true,
281→                editorMode: 'canvas',
282→                initialTitle: remixTitle,
283→                initialCanvasDoc: postData?.canvasDoc || null,
284→                remixSource: {
285→                    journalId: postData?.journalId,
286→                    authorName: postData?.name || 'Unknown'
287→                }
288→            }
289→        });
290→    }
291→
292→    const handleCLoseComments = () => {
293→        setShowCommentsContainer(false);
294→    }
295→
296→    useEffect(() => {
297→        if (!postData) return;
298→        setLikesCount(normalizeCount(postData?.likesCount));
299→        setBookmarkCounts(normalizeCount(postData?.bookmarksCount));
300→        setIsliked(normalizeInteractionFlag(postData?.isLiked));
301→        setIsBookmarked(normalizeInteractionFlag(postData?.isBookmarked));
302→    }, [postData?.likesCount, postData?.bookmarksCount, postData?.isLiked, postData?.isBookmarked]);
303→
304→    useEffect(() => {
305→        const hideBackBttn = () => {
306→            setShowBackButton(false);
307→            if (timeOutRef.current) {
308→                clearTimeout(timeOutRef.current);
309→            }
310→            timeOutRef.current = setTimeout(() => {
311→                setShowBackButton(true);
312→            }, 300);
313→        }
314→
315→        document.addEventListener('scroll', hideBackBttn, true);
316→        return () => {
317→            if (timeOutRef.current) {
318→                clearTimeout(timeOutRef.current);
319→            }
320→            document.removeEventListener('scroll', hideBackBttn, true);
321→        }
322→    }, []);
323→
324→    if (isLoadingJournalById || isLoadingFollows) {
325→        return (
326→            <div className="cv-loading">
327→                <MoonLoader loading={isLoadingJournalById || isLoadingFollows} color="var(--loader-color)" size={25} />
328→            </div>
329→        )
330→    }
331→
332→    if (!postData) {
333→        return (
334→            <div className="cv-loading">
335→                <p>Post is unavailable.</p>
336→                <button onClick={handleBackLocation} className="cv-back-btn" style={{ marginTop: "12px" }}>
337→                    Go back
338→                </button>
339→            </div>
340→        )
341→    }
342→
343→    return (
344→        <>
345→            {showCommentsContainer && (
346→                <AnimatePresence>
347→                    <CommentSection onclose={handleCLoseComments} postId={postData?.journalId} receiverId={postData?.userId} />
348→                </AnimatePresence>
349→            )}
350→
351→            <div ref={contentRef} className="cv-container">
352→                {/* Back header */}
353→                <AnimatePresence>
354→                    {showBackButton && (
355→                        <motion.div
356→                            className="cv-header"
357→                            initial={{ opacity: 0 }}
358→                            animate={{ opacity: 1, transition: { duration: 0.15 } }}
359→                            exit={{ opacity: 0, transition: { duration: 0.15 } }}
360→                        >
361→                            <button onClick={handleBackLocation} className="cv-back-btn">
