 1→const ParseContent = (contentString) => {
 2→    if(typeof contentString !== 'string' || !contentString.trim()){
 3→        return {
 4→            text: [],
 5→            slicedText: '',
 6→            images: [],
 7→            firstImage: null,
 8→            wholeText: '',
 9→        };
10→    }
11→    //sample json data to be passed here..
12→
13→    // {'root': {
14→    //     'children': [
15→    //         {
16→    //             type: 'paragraph', 
17→    //             "children": [
18→    //                 {
19→    //                     'type': 'text',
20→    //                     'text': 'some text'
21→    //                 },
22→    //                 {
23→    //                     'type': 'image',
24→    //                     'src': "https://hufaxmqdofaycnhdzrxf.supabase.co/...webp",
25→    //                     'width': 500,
26→    //                     'height': 500
27→    //                 }
28→    //             ]
29→    //         },
30→    //     ]
31→    // }}
32→
33→
34→    try {
35→        const content = JSON.parse(contentString);
36→        const root = content.root;
37→        const children = root?.children || [];
38→        
39→        // console.log(children)
40→        const parsedData = {
41→            text: [],
42→            slicedText: [],
43→            images: [],
44→            firstImage: null,
45→            wholeText: null,
46→        };
47→        const extractFromNodes = (nodes) =>{
48→            nodes.forEach((node) => {
49→                if(node.type === 'paragraph' || node.type === 'heading'){
50→                    //extract text
51→                    const textNodes = node.children?.filter((child) => child.type === "text") || [];
52→                    const paragraphText = textNodes.map((child) => child.text).join(" "); //join all the array of text into one text form
53→
54→                    if(paragraphText.trim()) parsedData.text.push(paragraphText);
55→
56→                    const imageNodes = node.children?.filter((child) => child.type === 'image') || [];
57→
58→                    imageNodes.forEach((img) => {
59→                        const imageData = {src: img.src, width: img.width, height: img.height};
60→                        parsedData.images.push(imageData)
61→                        if(!parsedData.firstImage) parsedData.firstImage = imageData; //check if firstImage has no image
62→                    })
63→                }
64→
65→                if (node.type === "image") {
66→                    const imageData = { src: node.src, width: node.width, height: node.height };
67→                    parsedData.images.push(imageData);
68→                    if (!parsedData.firstImage) parsedData.firstImage = imageData;
69→                 }
70→
71→                if(node.children) extractFromNodes(node.children);
72→            });
73→        }
74→
75→        extractFromNodes(children);
76→
77→        const combinedText = parsedData.text.join(' ').trim();
78→        parsedData.wholeText = combinedText;
79→        parsedData.slicedText = combinedText.length > 215 ? `${combinedText.substring(0, 215)}...` : combinedText;
80→        
81→        return parsedData; //return the parsedData
82→        } catch (error) {
83→            console.error('Error parsing content:', error);
84→            return {
85→                text: [],
86→                slicedText: '',
87→                images: [],
88→                firstImage: null,
89→                wholeText: '',
90→            };
91→        }
92→}
93→export default ParseContent;
